from flask import Flask, request, jsonify
from web3 import Web3
import os

app = Flask(__name__)

# Initialize Web3
w3 = Web3(Web3.HTTPProvider(os.getenv('INFURA_URL')))

def verify_signature(message, signature, address):
    message_hash = w3.keccak(text=message)
    recovered_address = w3.eth.account.recoverHash(message_hash, signature=signature)
    return recovered_address.lower() == address.lower()

@app.route('/verify', methods=['POST'])
def verify():
    data = request.json
    message = data.get('message')
    signature = data.get('signature')
    address = data.get('address')

    if not message or not signature or not address:
        return jsonify({'error': 'Invalid input'}), 400

    if verify_signature(message, signature, address):
        return jsonify({'status': 'success', 'message': 'Signature verified'}), 200
    else:
        return jsonify({'status': 'failure', 'message': 'Signature verification failed'}), 401

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=int(os.getenv('PORT', 5000)))